'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useAuth } from '@/context/AuthContext';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase/firebase';
import Navbar from '@/components/Navbar';

const checkProfileStatus = (instData) => {
    const required = [
        instData.basicDetails?.instituteName,
        instData.basicDetails?.city,
        instData.basicDetails?.yearEstablished,
        instData.contact?.primaryEmail,
        instData.about?.description,
    ];
    const completed = required.filter(Boolean).length;
    const progress = Math.round((completed / required.length) * 100);
    const isComplete = progress === 100;

    return {
        progress,
        isComplete,
        checklist: {
            'Basic Information (Name, City)': Boolean(instData.basicDetails?.instituteName && instData.basicDetails?.city),
            'About Your Institution': Boolean(instData.about?.description),
            'Contact Details': Boolean(instData.contact?.primaryEmail),
            'Upload a Logo': Boolean(instData.media?.logoUrl),
        }
    };
};

export default function InstitutionDashboard() {
    const { user, loading: authLoading } = useAuth();
    const [status, setStatus] = useState('loading');
    const [profileStatus, setProfileStatus] = useState({ progress: 0, isComplete: false, checklist: {} });

    useEffect(() => {
        if (!user) return;

        const fetchInstitutionData = async () => {
            try {
                const instDoc = await getDoc(doc(db, 'institutions', user.uid));
                if (instDoc.exists()) {
                    const instData = instDoc.data();
                    const statusInfo = checkProfileStatus(instData);
                    setProfileStatus(statusInfo);
                    setStatus(statusInfo.isComplete ? 'complete' : 'pending');
                } else {
                    setStatus('pending');
                    setProfileStatus({ progress: 10, isComplete: false, checklist: {} });
                }
            } catch (error) {
                console.error("Error fetching institution status:", error);
                setStatus('error');
            }
        };

        fetchInstitutionData();
    }, [user]);

    if (authLoading || status === 'loading') {
        return <div className="page-loading">Loading your dashboard...</div>;
    }

    return (
        <div style={{ backgroundColor: 'var(--bg-secondary)', minHeight: '100vh' }}>
            <Navbar />
            <main className="container" style={{ padding: '2rem 1rem' }}>
                <h1 style={{ color: 'var(--color-maroon)', marginBottom: '2rem' }}>Institution Dashboard</h1>
                
                {status === 'pending' ? (
                    <div className="card glass-panel" style={{ maxWidth: '700px', margin: '0 auto' }}>
                        <h2 className="text-2xl font-bold mb-2">Complete Your Institution Profile</h2>
                        <p className="text-gray-600 mb-6">Finish these steps to make your institution visible to students and artists.</p>
                        
                        {/* Progress Bar */}
                        <div style={{ marginBottom: '1.5rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                <span>Profile Completion</span>
                                <span style={{ fontWeight: 'bold' }}>{profileStatus.progress}%</span>
                            </div>
                            <div style={{ background: '#e0e0e0', borderRadius: '10px', height: '12px', overflow: 'hidden' }}>
                                <div style={{ width: `${profileStatus.progress}%`, background: 'var(--color-maroon)', height: '100%' }}></div>
                            </div>
                        </div>

                        {/* Checklist */}
                        <div style={{ marginBottom: '2rem' }}>
                            <h3 style={{ fontWeight: 'bold', marginBottom: '1rem' }}>Required Steps:</h3>
                            <ul style={{ listStyle: 'none', padding: 0 }}>
                                {Object.entries(profileStatus.checklist).map(([key, value]) => (
                                    <li key={key} style={{ display: 'flex', alignItems: 'center', marginBottom: '0.75rem' }}>
                                        <span style={{ color: value ? '#22c55e' : '#9ca3af', marginRight: '0.75rem' }}>
                                            {value ? '✅' : '⬜'}
                                        </span>
                                        <span>{key}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>

                        <Link href="/institution/onboarding" className="btn-primary" style={{ display: 'block', textAlign: 'center', padding: '1rem', fontSize: '1.1rem' }}>
                            Continue to Profile Setup
                        </Link>
                    </div>
                ) : (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        <div className="card">
                            <h3>Profile Management</h3>
                            <p>Update courses, faculty, and gallery.</p>
                            <Link href="/institution/manage-profile" className="btn-secondary mt-4 inline-block">Edit Profile</Link>
                        </div>
                        <div className="card">
                            <h3>Student Inquiries</h3>
                            <p>View and respond to inquiries from potential students.</p>
                            <Link href="/institution/inquiries" className="btn-secondary mt-4 inline-block">View Inquiries</Link>
                        </div>
                        <div className="card">
                            <h3>Artist Network</h3>
                            <p>Connect with affiliated artists and performers.</p>
                            <Link href="/institution/artists" className="btn-secondary-disabled mt-4 inline-block">Coming Soon</Link>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
}
